function i(r,n){const t=Math.pow(10,n);return Math.round((r+Number.EPSILON)*t)/t}function e(r,n){if(r<=0||n<=0)throw new Error("Espessura e largura devem ser positivas.");return r*n}function a(r,n,t){if(r<=0)throw new Error(`Metros lineares deve ser positivo. Recebido: ${r}`);if(n<=0||t<=0)throw new Error(`Dimensões inválidas (espessura: ${n}m, largura: ${t}m). Cadastre as dimensões do produto antes de realizar conversões.`);const o=e(n,t);return i(r*o,4)}function s(r,n,t){if(r<0)throw new Error(`Volume não pode ser negativo. Recebido: ${r}`);if(n<=0||t<=0)throw new Error(`Dimensões inválidas (espessura: ${n}m, largura: ${t}m).`);if(r===0)return 0;const o=e(n,t);return i(r/o,2)}function m(r,n){return r!=null&&n!=null&&r>0&&n>0}function c(r){return r.toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2})}function f(r){return r.toLocaleString("pt-BR",{minimumFractionDigits:4,maximumFractionDigits:4})}function d(r,n){return`${(r*1e3).toFixed(0)}mm × ${(n*1e3).toFixed(0)}mm`}export{f as a,d as b,e as c,m as d,c as f,a as l,s as m};
